logger = system.util.getLogger('StateTimeline')
try:
	runID = value
	if runID is None:
		return []

	sql = """
	SELECT sh.startdatetime, sh.enddatetime, sh.reasonname,
	       COALESCE(sr.planneddowntime, FALSE) AS planned,
	       COALESCE(sr.recorddowntime, FALSE) AS is_downtime
	FROM statehistory sh
	LEFT JOIN statereason sr ON sh.statereasonid = sr.id
	WHERE sh.runid = ?
	ORDER BY sh.startdatetime
	"""
	ds = system.db.runPrepQuery(sql, [runID], 'mes_core')

	running = []
	unplanned = []
	planned = []

	for row in range(ds.getRowCount()):
		start = ds.getValueAt(row, 'startdatetime')
		end = ds.getValueAt(row, 'enddatetime')
		is_dt = ds.getValueAt(row, 'is_downtime')
		is_planned = ds.getValueAt(row, 'planned')

		if start is None or end is None:
			continue

		entry = {'x': 'Line 1', 'y': [int(start.getTime()), int(end.getTime())]}

		if not is_dt:
			running.append(entry)
		elif is_planned:
			planned.append(entry)
		else:
			unplanned.append(entry)

	return [
		{'name': 'Running', 'data': running},
		{'name': 'Unplanned DT', 'data': unplanned},
		{'name': 'Planned DT', 'data': planned}
	]
except Exception as e:
	logger.error('StateTimeline error: ' + str(e))
	return []

